#include <stdio.h>

void WriteToLogFile(FILE *logfile, const char* error_msg){
    if (logfile != NULL){
        fprintf(logfile, "%s\n", error_msg);
    } else {
        printf("Error: Unable to open the log file.\n");
    }
}